/**
 * @param {number} n The number of rows.
 * @param {number} m The number of columns.
 * @param {number[][]} sources Array of sources [r, c, color].
 * @return {number[][]} The final color grid.
 */
function solve(n, m, sources) {
    // Initialize the grid with 0 (uncolored)
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Use a min-heap (Priority Queue) to store the propagation front.
    // Each element in the heap will be: [time, color, r, c]
    // We use time as the primary key for BFS/Dijkstra-like expansion.
    // Since we want to process cells by the earliest time they are reached, a standard BFS queue structure works, 
    // but we need to handle the color dominance rule.

    // Let's reframe: this is a multi-source shortest path problem where the "cost" is time, 
    // and tie-breaking favors higher colors.

    // Priority Queue structure: [time, -color, r, c]
    // We use -color because we want to process higher colors first if times are equal, 
    // but since time is the primary key, we just need to ensure that if times are equal, 
    // the one with the max color is handled correctly.

    // Standard BFS approach: process layer by layer (time step by time step).
    // Since multiple colors can reach a cell at the same time, we need to know the arrival time 
    // and the color that arrived at that time.

    // dist[r][c] will store an object { time: t, color: c } representing the best known state.
    // Initialize time to infinity and color to 0.
    const dist = Array(n).fill(0).map(() => Array(m).fill(null).map(() => ({ time: Infinity, color: 0 })));

    // The queue will store [r, c, time, color] for cells that have been newly colored or updated.
    const queue = [];

    for (const [r, c, color] of sources) {
        const initialTime = 0;
        dist[r][c] = { time: 0, color: color };
        queue.push([r, c, 0, color]);
        grid[r][c] = color;
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    let head = 0;
    while (head < queue.length) {
        const [r, c, time, color] = queue[head++];

        // Current cell (r, c) has been reached at 'time' with 'color'.

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const nextTime = time + 1;
                const existing = dist[nr][nc];

                // Check if this new arrival is better than the current best known state for (nr, nc).
                let update = false;

                if (nextTime < existing.time) {
                    // Arrived earlier: Always update.
                    update = true;
                } else if (nextTime === existing.time) {
                    // Arrived at the same time: Update if the new color is greater.
                    if (color > existing.color) {
                        update = true;
                    }
                }
                // If nextTime > existing.time, no update needed.

                if (update) {
                    // Update the best known state
                    dist[nr][nc] = { time: nextTime, color: color };

                    // Update the grid color immediately based on the best known state (this handles the final state requirement)
                    grid[nr][nc] = color;

                    // Add to queue for further propagation
                    queue.push([nr, nc, nextTime, color]);
                }
            }
        }
    }

    return grid;
}

