using namespace std;

// Define a structure or use a tuple/vector to store distance/color information
struct CellState {
    int time;
    long long color;

    // Custom comparison: we want to prioritize smaller time, and for equal time, larger color.
    // This is used for Dijkstra-like relaxation, but since we are using a simple queue (BFS style)
    // and the update logic handles the priority, we just need a way to compare.
    // In the BFS approach derived from the reference, we are not strictly using a PQ, 
    // but rather checking the relaxation condition (update logic).
};

// We will use a simple queue and rely on the relaxation logic to mimic the outcome of a Dijkstra/Multi-source BFS.

std::vector<std::vector<long long>> solve(long long n, long long m, std::vector<std::vector<long long>> sources) {
    // Grid to store the final color. Initialize to 0 (uncolored).
    std::vector<std::vector<long long>> grid(n, std::vector<long long>(m, 0));

    // dist[r][c] stores the best known state for cell (r, c): {time, color}
    // Time is initialized to infinity, color to 0.
    const int INF = std::numeric_limits<int>::max();
    std::vector<std::vector<CellState>> dist(n, std::vector<CellState>(m, {INF, 0}));

    // Queue for BFS/propagation. Stores: {r, c, time, color}
    // Since we are processing based on arrival time, a standard FIFO queue suffices if the relaxation logic is correct.
    std::queue<std::tuple<int, int, int, long long>> q;

    // Initialize sources
    for (const auto& source : sources) {
        int r = source[0];
        int c = source[1];
        long long color = source[2];

        // Sources are at time 0.
        dist[r][c] = {0, color};
        grid[r][c] = color;
        q.emplace(r, c, 0, color);
    }

    int dr[] = {0, 0, 1, -1};
    int dc[] = {1, -1, 0, 0};

    while (!q.empty()) {
        auto [r, c, time, color] = q.front();
        q.pop();

        for (int i = 0; i < 4; ++i) {
            int nr = r + dr[i];
            int nc = c + dc[i];

