// We use time as the primary sorting criterion, then -color for max color priority at the same time.
// However, since we are using a standard queue/BFS structure based on time layers, 
// we adapt the logic to mimic Dijkstra's behavior implicitly or rely on the relaxation step.
// A simple FIFO queue combined with the relaxation logic (checking if the new path is better) 
// is sufficient for this specific problem structure (time increases by 1).

struct State {
    long long time;
    long long color;
    int r;
    int c;

    // For priority queue (if we were using Dijkstra's), we'd define operator< here.
    // Since we are using a standard queue structure based on relaxation, this struct is mainly for clarity.
};


vector<vector<long long>> solve(long long n, long long m, vector<vector<long long>> sources) {
    // grid will store the final color. Initialize to 0 (uncolored).
    vector<vector<long long>> grid(n, vector<long long>(m, 0));

    // dist[r][c] stores the best known state to reach (r, c): {time, color}
    // Initialize time to infinity (a large value) and color to 0.
    const long long INF_TIME = 2e18; // Sufficiently large time
    vector<vector<pair<long long, long long>>> dist(n, vector<pair<long long, long long>>(m, {INF_TIME, 0}));

    // Queue for BFS-like expansion: {r, c, time, color}
    // Using std::queue for FIFO processing, as time always increases by 1.
    queue<State> q;

    // Initialize sources
    for (const auto& source : sources) {
        long long r = source[0];
        long long c = source[1];
        long long color = source[2];

        // Initial state is time 0
        if (dist[r][c].first > 0) {
            dist[r][c] = {0, color};
            grid[r][c] = color;
            q.push({0, color, (int)r, (int)c});
        }
    }

    const int directions[4][2] = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

    while (!q.empty()) {
        State current = q.front();
        q.pop();

        long long r = current.r;
        long long c = current.c;
        long long time = current.time;
        long long color = current.color;

        // Optimization: If the state pulled from the queue is worse than the currently recorded best state, skip it.
        // This handles redundant entries in the queue resulting from multiple paths reaching the same node before final relaxation.
        if (time > dist[r][c].first || (time == dist[r][c].first && color < dist[r][c].second)) {
            continue;
